// =============================================================
// Build Prompt — resolve variables in prompt template
// =============================================================

const item = $input.first().json;
const { resolvedConfig, variableContext, tenantId } = item;

const prompt = resolvedConfig.prompt || '';
const outputSchema = resolvedConfig.output_schema || [];

// Build context string from variable context
const contextEntries = Object.entries(variableContext)
  .map(([k, v]) => `${k}: ${JSON.stringify(v)}`)
  .join('\n');

return {
  json: {
    ...item,
    aiPayload: {
      prompt,
      context: contextEntries,
      output_schema: outputSchema,
      tenant_id: tenantId,
    },
  }
};

// =============================================================
// Parse AI Result — extract structured output from MiniMax Agent
// =============================================================
// MiniMax returns: { content: [{ type: 'thinking', ... }, { type: 'text', text: '```json\n{...}\n```' }] }
// We need: find 'text' entry, strip markdown code fences, parse JSON.
// =============================================================

function stripCodeFences(str) {
  const match = str.match(/```(?:json)?\s*([\s\S]*?)```/);
  return match ? match[1].trim() : str.trim();
}

function extractTextContent(aiOutput) {
  // Case 1: content array with typed entries (MiniMax/Claude format)
  if (aiOutput && Array.isArray(aiOutput.content)) {
    const textEntry = aiOutput.content.find(c => c.type === 'text');
    if (textEntry && textEntry.text) return textEntry.text;
    // Fallback: first entry with text
    const anyText = aiOutput.content.find(c => c.text);
    if (anyText) return anyText.text;
  }
  // Case 2: direct text field
  if (aiOutput && aiOutput.text) return aiOutput.text;
  // Case 3: stringified response
  return JSON.stringify(aiOutput);
}

try {
  const aiOutput = $('Call MiniMax Agent').first().json;
  const rawText = extractTextContent(aiOutput);
  const cleaned = stripCodeFences(rawText);

  let parsedOutput;
  try {
    parsedOutput = JSON.parse(cleaned);
  } catch {
    parsedOutput = { aiResponse: rawText };
  }

  const item = $('Build Prompt').first().json;
  return {
    json: {
      ...item,
      stepResult: {
        success: true,
        outputPayload: parsedOutput,
      },
    }
  };
} catch (e) {
  const item = $('Build Prompt').first().json;
  return {
    json: {
      ...item,
      stepResult: {
        success: false,
        error: `AI action failed: ${e.message}`,
      },
    }
  };
}
